class MessageValidator:
    def __init__(self, secret_key: Optional[str] = None):
        self.secret_key = secret_key or os.environ.get('MESSAGE_SECRET_KEY', '')
    
    def validate_signature(self, message_body: str, signature: str) -> bool:
        if not self.secret_key:
            return True
        
        expected_signature = hmac.new(
            self.secret_key.encode(),
            message_body.encode(),
            hashlib.sha256
        ).hexdigest()
        
        return hmac.compare_digest(expected_signature, signature)
    
    def validate_message_structure(self, message: Dict[str, Any]) -> bool:
        required_fields = ['type', 'payload', 'timestamp']
        return all(field in message for field in required_fields)
    
    def validate_timestamp(self, timestamp: str, max_age_seconds: int = 3600) -> bool:
        try:
            msg_time = datetime.fromisoformat(timestamp.replace('Z', '+00:00'))
            current_time = datetime.utcnow()
            age = (current_time - msg_time.replace(tzinfo=None)).total_seconds()
            return age <= max_age_seconds
        except (ValueError, AttributeError):
            return False


class MessageHandler:
    def __init__(self):
        self.handlers: Dict[str, Callable] = {}
    
    def register(self, message_type: str, handler: Callable):
        if not callable(handler):
            raise ValueError(f"Handler for {message_type} must be callable")
        self.handlers[message_type] = handler
    
    def handle(self, message_type: str, payload: Dict[str, Any]) -> Any:
        handler = self.handlers.get(message_type)
        if not handler:
            raise ValueError(f"No handler registered for message type: {message_type}")
        return handler(payload)
    
    def has_handler(self, message_type: str) -> bool:
        return message_type in self.handlers


class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30,
        secret_key: Optional[str] = None
    ):
        self.queue_url = queue_url
        self.max_messages = min(max_messages, 10)
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.running = False
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.message_handler = MessageHandler()
        self.validator = MessageValidator(secret_key)
        
        self._validate_queue_url()
    
    def _validate_queue_url(self):
        if not self.queue_url or not self.queue_url.startswith('https://'):
            raise ValueError("Invalid queue URL")
        
        try:
            self.sqs_client.get_queue_attributes(
                QueueUrl=self.queue_url,
                AttributeNames=['QueueArn']
            )
        except ClientError as e:
            logger.error(f"Failed to validate queue: {e}")
            raise
    
    def register_handler(self, message_type: str, handler: Callable):
        self.message_handler.register(message_type, handler)
    
    def _parse_message_body(self, body: str) -> Dict[str, Any]:
        try:
            return json.loads(body)
        except json.JSONDecodeError as e:
            logger.error(f"Failed to parse message body: {e}")
            raise ValueError("Invalid JSON in message body")
    
    def _validate_message(self, message_data: Dict[str, Any], raw_body: str) -> bool:
        if not self.validator.validate_message_structure(message_data):
            logger.warning("Message missing required fields")
            return False
        
        signature = message_data.get('signature', '')
        if signature and not self.validator.validate_signature(raw_body, signature):
            logger.warning("Message signature validation failed")
            return False
        
        if not self.validator.validate_timestamp(message_data.get('timestamp', '')):
            logger.warning("Message timestamp validation failed")
            return False
        
        message_type = message_data.get('type', '')
        if not message_type or not isinstance(message_type, str):
            logger.warning("Invalid message type")
            return False
        
        if len(message_type) > 100:
            logger.warning("Message type too long")
            return False
        
        return True
    
    def _process_message(self, message: Dict[str, Any]) -> bool:
        try:
            body = message.get('Body', '')
            receipt_handle = message.get('ReceiptHandle', '')
            
            if not body or not receipt_handle:
                logger.warning("Message missing body or receipt handle")
                return False
            
            message_data = self._parse_message_body(body)
            
            if not self._validate_message(message_data, body):
                logger.warning(f"Message validation failed: {message.get('MessageId')}")
                return False
            
            message_type = message_data['type']
            payload = message_data['payload']
            
            if not self.message_handler.has_handler(message_type):
                logger.warning(f"No handler for message type: {message_type}")
                return False
            
            logger.info(f"Processing message type: {message_type}")
            result = self.message_handler.handle(message_type, payload)
            
            logger.info(f"Successfully processed message: {message.get('MessageId')}")
            return True
            
        except Exception as e:
            logger.error(f"Error processing message: {e}", exc_info=True)
            return False
    
    def _delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info("Message deleted from queue")
        except ClientError as e:
            logger.error(f"Failed to delete message: {e}")
    
    def _change_message_visibility(self, receipt_handle: str, timeout: int):
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
        except ClientError as e:
            logger.error(f"Failed to change message visibility: {e}")
    
    def _poll_messages(self):
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            
            return response.get('Messages', [])
            
        except ClientError as e:
            logger.error(f"Error polling messages: {e}")
            return []
    
    def process_single_batch(self):
        messages = self._poll_messages()
        
        if not messages:
            logger.debug("No messages received")
            return 0
        
        logger.info(f"Received {len(messages)} messages")
        processed_count = 0
        
        for message in messages:
            receipt_handle = message.get('ReceiptHandle')
            
            try:
                success = self._process_message(message)
                
                if success:
                    self._delete_message(receipt_handle)
                    processed_count += 1
                else:
                    self._change_message_visibility(receipt_handle, 0)
                    
            except Exception as e:
                logger.error(f"Unexpected error processing message: {e}", exc_info=True)
                if receipt_handle:
                    self._change_message_visibility(receipt_handle, 0)
        
        return processed_count
    
    def start(self, poll_interval: int = 0):
        self.running = True
        logger.info("Starting SQS worker")
        
        while self.running:
            try:
                processed = self.process_single_batch()
                logger.info(f"Processed {processed} messages in this batch")
                
                if poll_interval > 0 and processed == 0:
                    time.sleep(poll_interval)
                    
            except KeyboardInterrupt:
                logger.info("Received interrupt signal")
                self.stop()
            except Exception as e:
                logger.error(f"Unexpected error in worker loop: {e}", exc_info=True)
                time.sleep(5)
    
    def stop(self):
        logger.info("Stopping SQS worker")
        self.running = False


